fz_drop_flotilla(fz_context *ctx, fz_flotilla *f);

/*
	How many rafts in this flotilla?
*/
int
fz_flotilla_size(fz_context *ctx, fz_flotilla *flot);

/*
	Return the bounds of the ith raft in the flotilla.
*/
