2239		fz_walk_path(ctx, path, &walker, &rd);
2240	
2241		if (rd.fail)
2242			return 0;
2243	
2244		if (rd.count == 2)
2245		{
2246			stash_point(&rd, rd.corners[1].x, rd.corners[1].y);
2247			stash_point(&rd, rd.corners[0].x, rd.corners[0].y);
2248		}
2249	
2250		for (i = 0 ; i < 4; i++)
2251		{
2252			fz_point p = fz_transform_point(rd.corners[i], ctm);
2253	
2254			rd.corners[i].x = p.x;
2255			rd.corners[i].y = p.y;
2256		}
2257	
2258		/* So we have a 4 cornered path. Hopefully something like:
2259		 * 0---------1
2260		 * |         |
2261		 * 3---------2
2262		 * but it might be:
2263		 * 0---------3
2264		 * |         |
2265		 * 1---------2
2266		*/
2267		while (1)
2268		{
2269			d01x = rd.corners[1].x - rd.corners[0].x;
2270			d01y = rd.corners[1].y - rd.corners[0].y;
2271			d01 = d01x * d01x + d01y * d01y;
2272			d03x = rd.corners[3].x - rd.corners[0].x;
2273			d03y = rd.corners[3].y - rd.corners[0].y;
2274			d03 = d03x * d03x + d03y * d03y;
2275			if(d01 < d03)
2276			{
2277				/* We are the latter case. Transpose it. */
