2503	
2504		b->bbox = bbox;
2505		b->u.v.flags = flags;
2506		b->u.v.argb = argb;
2507	}
2508	
2509	typedef struct
2510	{
2511		fz_stext_device *dev;
2512		fz_matrix ctm;
2513		uint32_t argb;
2514		uint32_t flags;
2515		fz_stext_page *page;
2516		fz_rect seg_bounds;
2517		fz_rect leftovers;
2518		fz_rect pending;
2519		int count;
2520		fz_point p[5];
2521		int id;
2522		float exp;
2523	} split_path_data;
2524	
2525	static void
2526	maybe_rect(fz_context *ctx, split_path_data *sp)
2527	{
2528		int rect = 0;
2529		int i;
2530		fz_rect leftovers;
2531	
2532		if (sp->count >= 3)
2533		{
2534			/* Allow for multiple monotonic points in a horizontal or vertical line,
2535			 * such as seen in borders of tables where each column or row is written
2536			 * individually. (e.g. move 0 0 line 100 0 line 200 0 line 300 0) */
2537			if (feq(sp->p[sp->count-1].x, sp->p[sp->count-2].x) &&
2538				feq(sp->p[sp->count-1].x, sp->p[sp->count-3].x) &&
2539				((sp->p[sp->count-1].y <= sp->p[sp->count-2].y && sp->p[sp->count-2].y <= sp->p[sp->count-3].y) ||
2540				(sp->p[sp->count-1].y >= sp->p[sp->count-2].y && sp->p[sp->count-2].y >= sp->p[sp->count-3].y)))
2541			{
2542				/*  y---->y---->y - Remove the central y */
2543				sp->p[sp->count-2].y = sp->p[sp->count-1].y;
2544				sp->count--;
2545			}
2546			else if (feq(sp->p[sp->count-1].y, sp->p[sp->count-2].y) &&
2547				feq(sp->p[sp->count-1].y, sp->p[sp->count-3].y) &&
2548				((sp->p[sp->count-1].x <= sp->p[sp->count-2].x && sp->p[sp->count-2].x <= sp->p[sp->count-3].x) ||
2549				(sp->p[sp->count-1].x >= sp->p[sp->count-2].x && sp->p[sp->count-2].x >= sp->p[sp->count-3].x)))
2550			{
2551				/*  x---->x---->x - Remove the central x */
2552				sp->p[sp->count-2].x = sp->p[sp->count-1].x;
2553				sp->count--;
2554			}
2555		}
2556	
2557		if (sp->count >= 0)
2558		{
2559			if (sp->count == 3)
2560			{
2561				/* Allow for "moveto A, lineto B, lineto A, close" */
2562				if (feq(sp->p[0].x, sp->p[2].x) && feq(sp->p[0].y, sp->p[2].y))
2563					sp->count = 2;
2564			}
2565			if (sp->count == 2)
2566			{
2567				if (feq(sp->p[0].x, sp->p[1].x) || feq(sp->p[0].y, sp->p[1].y))
2568					rect = 1; /* Count that as a rect */
2569			}
2570			else if (sp->count == 4 || sp->count == 5)
2571			{
2572				if (feq(sp->p[0].x, sp->p[1].x) && feq(sp->p[2].x, sp->p[3].x) && feq(sp->p[0].y, sp->p[3].y) && feq(sp->p[1].y, sp->p[2].y))
2573					rect = 1;
2574				else if (feq(sp->p[0].x, sp->p[3].x) && feq(sp->p[1].x, sp->p[2].x) && feq(sp->p[0].y, sp->p[1].y) && feq(sp->p[2].y, sp->p[3].y))
2575					rect = 1;
2576			}
2577			if (rect)
2578			{
2579				fz_rect bounds;
2580	
2581				bounds.x0 = bounds.x1 = sp->p[0].x;
2582				bounds.y0 = bounds.y1 = sp->p[0].y;
2583				for (i = 1; i < sp->count; i++)
2584					bounds = fz_include_point_in_rect(bounds, sp->p[i]);
2585				if (fz_is_valid_rect(sp->pending))
2586					add_vector(ctx, sp->page, sp->dev, sp->pending, sp->flags | FZ_STEXT_VECTOR_IS_RECTANGLE | FZ_STEXT_VECTOR_CONTINUES, sp->argb, sp->id, sp->exp);
2587				sp->pending = bounds;
2588				return;
2589			}
2590		}
2591	
2592		/* We aren't a rectangle! */
2593		leftovers = sp->seg_bounds;
2594	
2595		if (sp->dev->flags & (FZ_STEXT_CLIP_RECT | FZ_STEXT_CLIP))
2596			leftovers = fz_intersect_rect(leftovers, current_clip(ctx, sp->dev));
2597	
2598		if (fz_is_valid_rect(leftovers))
2599			sp->leftovers = fz_union_rect(sp->leftovers, leftovers);
2600	
2601		/* Remember we're not a rect. */
2602		sp->count = -1;
2603	}
2604	
2605	static void
2606	split_move(fz_context *ctx, void *arg, float x, float y)
2607	{
2608		split_path_data *sp = (split_path_data *)arg;
2609		fz_point p = fz_transform_point_xy(x, y, sp->ctm);
2610	
2611		maybe_rect(ctx, sp);
2612		sp->p[0] = p;
2613		sp->count = 1;
2614		sp->seg_bounds.x0 = sp->seg_bounds.x1 = p.x;
2615		sp->seg_bounds.y0 = sp->seg_bounds.y1 = p.y;
2616	}
2617	
2618	static void
2619	split_line(fz_context *ctx, void *arg, float x, float y)
2620	{
2621		split_path_data *sp = (split_path_data *)arg;
2622		fz_point p = fz_transform_point_xy(x, y, sp->ctm);
2623	
2624		sp->seg_bounds = fz_include_point_in_rect(sp->seg_bounds, p);
2625	
2626		if (sp->count >= 0)
2627		{
2628			/* Check for lines to the same point. */
2629			if (sp->count > 0 && feq(sp->p[sp->count-1].x, p.x) && feq(sp->p[sp->count-1].y, p.y))
2630				return;
2631			/* If we're still maybe a rect, just record the point. */
2632			if (sp->count < 4)
2633			{
2634				sp->p[sp->count++] = p;
2635				return;
2636			}
2637			/* Check for close line? */
2638			if (sp->count == 4)
2639			{
2640				if (feq(sp->p[0].x, p.x) && feq(sp->p[0].y, p.y))
2641				{
2642					/* We've just drawn a line back to the start point. */
2643					/* Needless saving of point, but it makes the logic
2644					 * easier elsewhere. */
2645					sp->p[sp->count++] = p;
2646					return;
2647				}
2648			}
2649			/* We can no longer be a rect. */
2650			sp->count = -1;
2651		}
2652	}
2653	
2654	static void
2655	split_curve(fz_context *ctx, void *arg, float x1, float y1, float x2, float y2, float x3, float y3)
2656	{
2657		split_path_data *sp = (split_path_data *)arg;
2658	
2659		sp->seg_bounds = fz_include_point_in_rect(sp->seg_bounds, fz_transform_point_xy(x1, y1, sp->ctm));
2660		sp->seg_bounds = fz_include_point_in_rect(sp->seg_bounds, fz_transform_point_xy(x2, y2, sp->ctm));
2661		sp->seg_bounds = fz_include_point_in_rect(sp->seg_bounds, fz_transform_point_xy(x3, y3, sp->ctm));
2662	
2663		/* We can no longer be a rect. */
2664		sp->count = -1;
2665	}
2666	
2667	static void
2668	split_close(fz_context *ctx, void *arg)
2669	{
2670		split_path_data *sp = (split_path_data *)arg;
2671	
2672		maybe_rect(ctx, sp);
2673		sp->count = 0;
2674	}
2675	
2676	
2677	static const
2678	fz_path_walker split_path_rects =
2679	{
2680		split_move,
2681		split_line,
2682		split_curve,
2683		split_close
2684	};
2685	
2686	static void
2687	add_vectors_from_path(fz_context *ctx, fz_stext_page *page, fz_stext_device *tdev, const fz_path *path, fz_matrix ctm, fz_colorspace *cs, const float *color, float alpha, fz_color_params cp, const fz_stroke_state *stroke, float exp)
2688	{
2689		int have_leftovers;
2690		split_path_data sp;
2691		int id = tdev->id;
2692		int trailing_moves_acceptable = (stroke == NULL || stroke->end_cap != FZ_LINECAP_ROUND);
2693	
2694		sp.dev = tdev;
2695		sp.ctm = ctm;
2696		sp.argb = hexrgba_from_color(ctx, cs, color, alpha);
2697		sp.flags = stroke ? FZ_STEXT_VECTOR_IS_STROKED : 0;
2698		sp.page = page;
2699		sp.count = 0;
2700		sp.leftovers = fz_empty_rect;
2701		sp.seg_bounds = fz_empty_rect;
2702		sp.pending = fz_empty_rect;
2703		sp.id = id;
2704		sp.exp = exp;
2705		fz_walk_path(ctx, path, &split_path_rects, &sp);
2706	
2707		have_leftovers = fz_is_valid_rect(sp.leftovers);
2708	
2709		if (!trailing_moves_acceptable || sp.count != 1)
2710			maybe_rect(ctx, &sp);
2711	
2712		if ((!trailing_moves_acceptable || sp.count != 1) && fz_is_valid_rect(sp.pending))
2713			add_vector(ctx, page, sp.dev, sp.pending, sp.flags | FZ_STEXT_VECTOR_IS_RECTANGLE | (have_leftovers ? FZ_STEXT_VECTOR_CONTINUES : 0), sp.argb, id, exp);
2714		if (have_leftovers)
2715			add_vector(ctx, page, sp.dev, sp.leftovers, sp.flags, sp.argb, id, exp);
2716	}
