2718	static void
2719	fz_stext_fill_path(fz_context *ctx, fz_device *dev, const fz_path *path, int even_odd, fz_matrix ctm, fz_colorspace *cs, const float *color, float alpha, fz_color_params cp)
2720	{
2721		fz_stext_device *tdev = (fz_stext_device*)dev;
2722		fz_stext_page *page = tdev->page;
2723		fz_rect path_bounds = fz_bound_path(ctx, path, NULL, ctm);
2724		fz_rect *bounds = actualtext_bounds(tdev);
2725	
2726		/* If we're in an actualtext, then update the bounds to include this content. */
2727		if (bounds != NULL)
2728			*bounds = fz_union_rect(*bounds, path_bounds);
2729	
2730		if (tdev->flags & FZ_STEXT_COLLECT_STYLES)
2731			check_for_strikeout(ctx, tdev, page, path, ctm, hexrgba_from_color(ctx, cs, color, alpha));
2732	
2733		if (tdev->flags & FZ_STEXT_COLLECT_VECTORS)
2734			add_vectors_from_path(ctx, page, tdev, path, ctm, cs, color, alpha, cp, NULL, 0);
2735	}
