2757	static void
2758	new_stext_struct(fz_context *ctx, fz_stext_page *page, fz_stext_block *block, fz_structure standard, const char *raw)
2759	{
2760		fz_stext_struct *str;
2761		size_t z;
2762	
2763		if (raw == NULL)
2764			raw = "";
2765		z = strlen(raw);
2766	
2767		str = fz_pool_alloc(ctx, page->pool, offsetof(fz_stext_struct, raw) + z + 1);
2768		str->first_block = NULL;
2769		str->last_block = NULL;
2770		str->standard = standard;
2771		str->parent = page->last_struct;
2772		str->up = block;
2773		memcpy(str->raw, raw, z+1);
2774	
2775		block->u.s.down = str;
2776	}
2777	
2778	fz_stext_block *
2779	fz_new_stext_struct(fz_context *ctx, fz_stext_page *page, fz_structure standard, const char *raw, int idx)
2780	{
2781		fz_stext_block *block;
2782	
2783		block = fz_pool_alloc(ctx, page->pool, sizeof *page->first_block);
2784		block->bbox = fz_empty_rect;
2785		block->prev = NULL;
2786		block->next = NULL;
2787		block->type = FZ_STEXT_BLOCK_STRUCT;
2788		block->u.s.index = idx;
2789		block->u.s.down = NULL;
2790		/* If this throws, we leak newblock but it's within the pool, so it doesn't matter. */
2791		new_stext_struct(ctx, page, block, standard, raw);
2792	
2793		return block;
2794	}
2795	
2796	
2797	static void
2798	fz_stext_begin_structure(fz_context *ctx, fz_device *dev, fz_structure standard, const char *raw, int idx)
2799	{
2800		fz_stext_device *tdev = (fz_stext_device*)dev;
2801		fz_stext_page *page = tdev->page;
2802		fz_stext_block *block, *le, *gt, *newblock;
2803	
2804		if (raw == NULL)
2805			raw = "";
2806	
2807		/* Find a pointer to the last block. */
2808		if (page->last_block)
2809		{
2810			block = page->last_block;
2811		}
2812		else if (page->last_struct)
2813		{
2814			block = page->last_struct->last_block;
2815		}
2816		else
2817		{
2818			block = page->first_block;
2819		}
2820	
2821		/* So block is somewhere in the content chain. Let's try and find:
2822		 *   le = the struct node <= idx before block in the content chain.
2823		 *   ge = the struct node >= idx after block in the content chain.
2824		 * Search backwards to start with.
2825		 */
2826		gt = NULL;
2827		le = block;
2828		while (le)
2829		{
2830			if (le->type == FZ_STEXT_BLOCK_STRUCT)
2831			{
2832				if (le->u.s.index > idx)
2833					gt = le;
2834				if (le->u.s.index <= idx)
2835					break;
2836			}
2837			le = le->prev;
2838		}
2839		/* The following loop copes with finding gt (the smallest block with an index higher
2840		 * than we want) if we haven't found it already. The while loop in here was designed
2841		 * to cope with 'block' being in the middle of a list. In fact, the way the code is
2842		 * currently, block will always be at the end of a list, so the while won't do anything.
2843		 * But I'm loathe to remove it in case we ever change this code to start from wherever
2844		 * we did the last insertion. */
2845		if (gt == NULL)
2846		{
2847			gt = block;
2848			while (gt)
2849			{
2850				if (gt->type == FZ_STEXT_BLOCK_STRUCT)
2851				{
2852					if (gt->u.s.index <= idx)
2853						le = gt;
2854					if (gt->u.s.index >= idx)
2855						break;
2856				}
2857				block = gt;
2858				gt = gt->next;
2859			}
2860		}
2861	
2862		if (le && le->u.s.index == idx)
2863		{
2864			/* We want to move down into the le block. Does it have a struct
2865			 * attached yet? */
2866			if (le->u.s.down == NULL)
2867			{
2868				/* No. We need to create a new struct node. */
2869				new_stext_struct(ctx, page, le, standard, raw);
2870			}
2871			else if (le->u.s.down->standard != standard || strcmp(raw, le->u.s.down->raw) != 0)
2872			{
2873				/* Yes, but it doesn't match the one we expect! */
2874				fz_warn(ctx, "Mismatched structure type!");
2875			}
2876			page->last_struct = le->u.s.down;
2877			page->last_block = le->u.s.down->last_block;
2878	
2879			return;
2880		}
2881	
2882		/* We are going to need to create a new block. Create a complete unlinked one here. */
2883		newblock = fz_new_stext_struct(ctx, page, standard, raw, idx);
2884	
2885		/* So now we just need to link it in somewhere. */
2886		if (gt)
2887		{
2888			/* Link it in before gt. */
2889			newblock->prev = gt->prev;
2890			if (gt->prev)
2891				gt->prev->next = newblock;
2892			else if (page->last_struct)
2893			{
2894				/* We're linking it in at the start under another struct! */
2895				assert(page->last_struct->first_block == gt);
2896				assert(page->last_struct->last_block != NULL);
2897				page->last_struct->first_block = newblock;
2898			}
2899			else
2900			{
2901				/* We're linking it in at the start of the page! */
2902				assert(page->first_block == gt);
2903				page->first_block = newblock;
2904			}
2905			gt->prev = newblock;
2906			newblock->next = gt;
2907			newblock->id = gt->id;
2908		}
2909		else if (block)
2910		{
2911			/* Link it in at the end of the list (i.e. after 'block') */
2912			newblock->prev = block;
2913			block->next = newblock;
2914			if (page->last_struct)
2915			{
2916				assert(page->last_struct->last_block == block);
2917				page->last_struct->last_block = newblock;
2918			}
2919			else
2920			{
2921				assert(page->last_block == block);
2922				page->last_block = newblock;
2923			}
2924			newblock->id = block->id;
2925		}
2926		else if (page->last_struct)
2927		{
2928			/* We have no blocks at all at this level. */
2929			page->last_struct->first_block = newblock;
2930			page->last_struct->last_block = newblock;
2931			newblock->id = page->last_struct->up->id;
2932		}
2933		else
2934		{
2935			/* We have no blocks at ANY level. */
2936			page->first_block = newblock;
2937			/* newblock will have an id of 0. Best we can do. */
2938		}
2939		/* Wherever we linked it in, that's where we want to continue adding content. */
2940		page->last_struct = newblock->u.s.down;
2941		page->last_block = NULL;
2942	}
2943	
2944	static void
2945	fz_stext_end_structure(fz_context *ctx, fz_device *dev)
2946	{
2947		fz_stext_device *tdev = (fz_stext_device*)dev;
2948		fz_stext_page *page = tdev->page;
2949		fz_stext_struct *str = page->last_struct;
2950	
2951		if (str == NULL)
2952		{
2953			fz_warn(ctx, "Structure out of sync");
2954			return;
2955		}
2956	
2957		page->last_struct = str->parent;
2958		if (page->last_struct == NULL)
2959		{
2960			page->last_block = page->first_block;
2961			/* Yuck */
2962			while (page->last_block->next)
2963				page->last_block = page->last_block->next;
2964		}
2965		else
2966		{
2967			page->last_block = page->last_struct->last_block;
2968		}
2969	}
