2977	fz_device *
2978	fz_new_stext_device_for_page(fz_context *ctx, fz_stext_page *page, const fz_stext_options *opts, int chapter_num, int page_num, fz_rect mediabox)
2979	{
2980		fz_stext_device *dev = fz_new_derived_device(ctx, fz_stext_device);
2981	
2982		dev->super.close_device = fz_stext_close_device;
2983		dev->super.drop_device = fz_stext_drop_device;
2984	
2985		dev->super.fill_text = fz_stext_fill_text;
2986		dev->super.stroke_text = fz_stext_stroke_text;
2987		dev->super.clip_text = fz_stext_clip_text;
2988		dev->super.clip_stroke_text = fz_stext_clip_stroke_text;
2989		dev->super.ignore_text = fz_stext_ignore_text;
2990		dev->super.begin_metatext = fz_stext_begin_metatext;
2991		dev->super.end_metatext = fz_stext_end_metatext;
2992	
2993		dev->super.fill_shade = fz_stext_fill_shade;
2994		dev->super.fill_image = fz_stext_fill_image;
2995		dev->super.fill_image_mask = fz_stext_fill_image_mask;
2996	
2997		if (opts)
2998		{
2999			dev->flags = opts->flags;
3000			if (opts->flags & FZ_STEXT_COLLECT_STRUCTURE)
3001			{
3002				dev->super.begin_structure = fz_stext_begin_structure;
3003				dev->super.end_structure = fz_stext_end_structure;
3004			}
3005			if (opts->flags & (FZ_STEXT_COLLECT_VECTORS | FZ_STEXT_COLLECT_STYLES))
