492	static void
493	find_table_pos(fz_stext_grid_positions *xs, float x0, float x1, int *ix0, int *ix1)
494	{
495		int i;
496	
497		*ix0 = -1;
498		*ix1 = -1;
499	
500		for (i = 1; i < xs->len; i++)
501			if (x0 < xs->list[i].pos)
502			{
503				*ix0 = i-1;
504				break;
505			}
506		for (; i < xs->len; i++)
507			if (x1 < xs->list[i].pos)
508			{
509				*ix1 = i-1;
510				break;
511			}
512		if (i == xs->len)
513			*ix1 = i-1;
514	}
