516	static void
517	run_to_xhtml(fz_context *ctx, fz_stext_block *block, fz_output *out);
518	
519	static unsigned int
520	grid_flags(fz_stext_grid_info *info, int x, int y)
521	{
522		if (info == NULL || x < 0 || y < 0 || x >= info->w || y >= info->h)
523			return 0;
524		return info->info[y * info->w + x].flags;
525	}
526	
527	static void
528	start_cell(fz_context *ctx, fz_output *out, fz_stext_grid_info *info, int x, int y)
529	{
530		unsigned int flags = grid_flags(info, x, y);
531		unsigned int flagsr = grid_flags(info, x+1, y);
532		unsigned int flagsb = grid_flags(info, x, y+1);
533		fz_write_string(ctx, out, "<td");
534		if (info == NULL)
535			return;
536		if ((flags & FZ_STEXT_GRID_L_BORDER) == 0 &&
537			(flags & FZ_STEXT_GRID_T_BORDER) == 0 &&
538			(flagsr & FZ_STEXT_GRID_L_BORDER) == 0 &&
539			(flagsb & FZ_STEXT_GRID_T_BORDER) == 0)
540			return;
541		fz_write_string(ctx, out, " style=\"border-style:");
542		if (flags & FZ_STEXT_GRID_T_BORDER)
543			fz_write_string(ctx, out, "solid ");
544		else
545			fz_write_string(ctx, out, "none ");
546		if (flagsr & FZ_STEXT_GRID_L_BORDER)
547			fz_write_string(ctx, out, "solid ");
548		else
549			fz_write_string(ctx, out, "none ");
550		if (flagsb & FZ_STEXT_GRID_T_BORDER)
551			fz_write_string(ctx, out, "solid ");
552		else
553			fz_write_string(ctx, out, "none ");
554		if (flags & FZ_STEXT_GRID_L_BORDER)
555			fz_write_string(ctx, out, "solid;\"");
556		else
557			fz_write_string(ctx, out, "none;\"");
558	
559	}
560	
561	static void
562	fz_print_stext_table_as_xhtml(fz_context *ctx, fz_output *out, fz_stext_block *block)
563	{
564		fz_stext_block *grid, *tr, *td;
565		int w, h;
566		int x, y;
567		uint8_t *cells;
568		int malformed = 0;
569	
570		for (grid = block; grid != NULL; grid = grid->next)
571			if (grid->type == FZ_STEXT_BLOCK_GRID)
572				break;
573		if (grid == NULL)
574		{
575			fz_warn(ctx, "Malformed table data");
576			return;
577		}
578		w = grid->u.b.xs->len;
579		h = grid->u.b.ys->len;
580		cells = fz_calloc(ctx, w, h);
581	
582		fz_try(ctx)
583		{
584			fz_write_printf(ctx, out, "<table style=\"border-collapse: collapse;\">\n");
585	
586			y = 0;
587			for (tr = grid->next; tr != NULL; tr = tr->next)
588			{
589				if (tr->type != FZ_STEXT_BLOCK_STRUCT || tr->u.s.down == NULL || tr->u.s.down->standard != FZ_STRUCTURE_TR)
590				{
591					malformed = 1;
592					continue;
593				}
594				fz_write_printf(ctx, out, "<tr>\n");
595				x = 0;
596				for (td = tr->u.s.down->first_block; td != NULL; td = td->next)
597				{
598					int x0, y0, x1, y1;
599					if (td->type != FZ_STEXT_BLOCK_STRUCT || td->u.s.down == NULL || td->u.s.down->standard != FZ_STRUCTURE_TD)
600					{
601						malformed = 1;
602						continue;
603					}
604					find_table_pos(grid->u.b.xs, td->bbox.x0, td->bbox.x1, &x0, &x1);
605					find_table_pos(grid->u.b.ys, td->bbox.y0, td->bbox.y1, &y0, &y1);
606					if (x0 < 0 || x1 < 0 || x1 >= w)
607					{
608						malformed = 1;
609						x0 = x;
610						x1 = x+1;
611					}
612					if (y0 < 0 || y1 < 0 || y1 >= h)
613					{
614						malformed = 1;
615						y0 = y;
616						y1 = y+1;
617					}
618					if (y < y0)
619					{
620						malformed = 1;
621						continue;
622					}
623					if (x > x0)
624					{
625						malformed = 1;
626					}
627					while (x < x0)
628					{
629						uint8_t *c = &cells[x + w*y];
630						if (*c == 0)
631						{
632							start_cell(ctx, out, grid->u.b.info, x, y);
633							fz_write_printf(ctx, out, "></td>");
634							*c = 1;
635						}
636						x++;
637					}
638					start_cell(ctx, out, grid->u.b.info, x, y);
639					if (x1 > x0+1)
640						fz_write_printf(ctx, out, " colspan=\"%d\"", x1-x0);
641					if (y1 > y0+1)
642						fz_write_printf(ctx, out, " rowspan=\"%d\"", y1-y0);
643					fz_write_string(ctx, out, ">");
644					run_to_xhtml(ctx, td->u.s.down->first_block, out);
645					fz_write_printf(ctx, out, "</td>\n");
646					for ( ; y0 < y1; y0++)
647						for (x = x0; x < x1; x++)
648						{
649							uint8_t *c = &cells[x + w*y0];
650							if (*c != 0)
651								malformed = 1;
652							*c = 1;
653						}
654				}
655				fz_write_printf(ctx, out, "</tr>\n");
656				y++;
657			}
658	
659			fz_write_printf(ctx, out, "</table>\n");
660		}
661		fz_always(ctx)
662			fz_free(ctx, cells);
663		fz_catch(ctx)
664			fz_rethrow(ctx);
665	
666		if (malformed)
667			fz_warn(ctx, "Malformed table data");
668	}
