698	static void
699	fz_print_style_end_xhtml(fz_context *ctx, fz_output *out, fz_font *font, int sup)
700	{
701		int is_mono = fz_font_is_monospaced(ctx, font);
702		int is_bold = fz_font_is_bold(ctx, font);
703		int is_italic = fz_font_is_italic(ctx, font);
704	
705		if (is_italic)
706			fz_write_string(ctx, out, "</i>");
707		if (is_bold)
708			fz_write_string(ctx, out, "</b>");
