714	
715	static float avg_font_size_of_line(fz_stext_char *ch)
716	{
717		float size = 0;
718		int n = 0;
719		if (!ch)
720			return 0;
721		while (ch)
722		{
723			size += ch->size;
724			++n;
725			ch = ch->next;
726		}
727		return size / n;
728	}
729	
730	static const char *tag_from_font_size(float size)
731	{
732		if (size >= 20) return "h1";
733		if (size >= 15) return "h2";
734		if (size >= 12) return "h3";
735		return "p";
736	}
737	
738	static void fz_print_stext_block_as_xhtml(fz_context *ctx, fz_output *out, fz_stext_block *block)
739	{
740		fz_stext_line *line;
741		fz_stext_char *ch;
742	
743		fz_font *font = NULL;
744		int sup = 0;
745		int sp = 1;
746		const char *tag = NULL;
747		const char *new_tag;
748	
749		for (line = block->u.t.first_line; line; line = line->next)
750		{
751			new_tag = tag_from_font_size(avg_font_size_of_line(line->first_char));
752			if (tag != new_tag)
753			{
754				if (tag)
755				{
756					if (font)
757						fz_print_style_end_xhtml(ctx, out, font, sup);
758					fz_write_printf(ctx, out, "</%s>", tag);
759				}
760				tag = new_tag;
761				fz_write_printf(ctx, out, "<%s>", tag);
762				if (font)
763					fz_print_style_begin_xhtml(ctx, out, font, sup);
764			}
765	
766			if (!sp)
767				fz_write_byte(ctx, out, ' ');
768	
769			for (ch = line->first_char; ch; ch = ch->next)
770			{
771				int ch_sup = detect_super_script(line, ch);
772				if (ch->font != font || ch_sup != sup)
773				{
774					if (font)
775						fz_print_style_end_xhtml(ctx, out, font, sup);
776					font = ch->font;
777					sup = ch_sup;
778					fz_print_style_begin_xhtml(ctx, out, font, sup);
779				}
780	
781				sp = (ch->c == ' ');
782				/* Skip hyphens on line joins */
783				if (ch->next == NULL && (line->flags & FZ_STEXT_LINE_FLAGS_JOINED) != 0 && fz_is_unicode_hyphen(ch->c))
784				{
785					sp = 1;
786					continue;
787				}
788				switch (ch->c)
789				{
790				default:
791					if (ch->c >= 32 && ch->c <= 127)
792						fz_write_byte(ctx, out, ch->c);
793					else
794						fz_write_printf(ctx, out, "&#x%x;", ch->c);
795					break;
796				case '<': fz_write_string(ctx, out, "&lt;"); break;
797				case '>': fz_write_string(ctx, out, "&gt;"); break;
798				case '&': fz_write_string(ctx, out, "&amp;"); break;
799				case '"': fz_write_string(ctx, out, "&quot;"); break;
800				case '\'': fz_write_string(ctx, out, "&apos;"); break;
801				}
802			}
803		}
804	
805		if (font)
806			fz_print_style_end_xhtml(ctx, out, font, sup);
807		fz_write_printf(ctx, out, "</%s>\n", tag);
808	}
809	
810	static void
811	fz_print_struct_as_xhtml(fz_context *ctx, fz_output *out, fz_stext_block *block)
812	{
813		const char *tag;
814	
815		if (block->u.s.down == NULL)
816			return;
817	
818		if (block->u.s.down->standard == FZ_STRUCTURE_TABLE)
819		{
820			fz_print_stext_table_as_xhtml(ctx, out, block->u.s.down->first_block);
821			return;
822		}
823	
824		tag = html_tag_for_struct(block->u.s.down);
825	
826		fz_write_printf(ctx, out, "<%s>\n", tag);
827	
828		run_to_xhtml(ctx, block->u.s.down->first_block, out);
829	
830		fz_write_printf(ctx, out, "</%s>\n", tag);
831	}
832	
833	static void
834	run_to_xhtml(fz_context *ctx, fz_stext_block *block, fz_output *out)
835	{
836		while (block)
837		{
838			switch(block->type)
839			{
840			case FZ_STEXT_BLOCK_IMAGE:
841				fz_print_stext_image_as_xhtml(ctx, out, block);
842				break;
843			case FZ_STEXT_BLOCK_TEXT:
844				fz_print_stext_block_as_xhtml(ctx, out, block);
845				break;
846			case FZ_STEXT_BLOCK_STRUCT:
847				fz_print_struct_as_xhtml(ctx, out, block);
848				break;
849			}
850			block = block->next;
851		}
852	}
853	
854	void
855	fz_print_stext_page_as_xhtml(fz_context *ctx, fz_output *out, fz_stext_page *page, int id)
856	{
857		fz_write_printf(ctx, out, "<div id=\"page%d\">\n", id);
858	
859		run_to_xhtml(ctx, page->first_block, out);
860	
