887	/* Detailed XML dump of the entire structured text data */
888	
889	static void
890	xml_write_char(fz_context *ctx, fz_output *out, int c)
891	{
892		switch (c)
893		{
894		case '<': fz_write_string(ctx, out, "&lt;"); break;
895		case '>': fz_write_string(ctx, out, "&gt;"); break;
896		case '&': fz_write_string(ctx, out, "&amp;"); break;
897		case '"': fz_write_string(ctx, out, "&quot;"); break;
898		case '\'': fz_write_string(ctx, out, "&apos;"); break;
899		default:
900			if (c >= 32 && c <= 127)
901				fz_write_printf(ctx, out, "%c", c);
902			else
903				fz_write_printf(ctx, out, "&#x%x;", c);
904			break;
905		}
906	}
907	
908	static void
909	as_xml(fz_context *ctx, fz_stext_block *block, fz_output *out, fz_stext_xml_flags flags)
910	{
911		fz_stext_line *line;
912		fz_stext_char *ch;
913		int i;
914	
915		while (block)
916		{
917			switch (block->type)
918			{
919			case FZ_STEXT_BLOCK_TEXT:
920				fz_write_printf(ctx, out, "<block ");
921				if (flags & FZ_STEXT_XML_FLAGS_POINTERS)
922					fz_write_printf(ctx, out, "p=\"%p\" ", block);
923				fz_write_printf(ctx, out, "bbox=\"%g %g %g %g\"",
924						block->bbox.x0, block->bbox.y0, block->bbox.x1, block->bbox.y1);
925				if (block->u.t.flags == FZ_STEXT_TEXT_JUSTIFY_UNKNOWN)
926					fz_write_printf(ctx, out, " justify=\"unknown\"");
927				if (block->u.t.flags == FZ_STEXT_TEXT_JUSTIFY_LEFT)
928					fz_write_printf(ctx, out, " justify=\"left\"");
929				if (block->u.t.flags == FZ_STEXT_TEXT_JUSTIFY_CENTER)
930					fz_write_printf(ctx, out, " justify=\"center\"");
931				if (block->u.t.flags == FZ_STEXT_TEXT_JUSTIFY_RIGHT)
932					fz_write_printf(ctx, out, " justify=\"right\"");
933				if (block->u.t.flags == FZ_STEXT_TEXT_JUSTIFY_FULL)
934					fz_write_printf(ctx, out, " justify=\"full\"");
935				fz_write_printf(ctx, out, ">\n");
936				for (line = block->u.t.first_line; line; line = line->next)
937				{
938					fz_font *font = NULL;
939					float size = 0;
940					const char *name = NULL;
941	
942					fz_write_printf(ctx, out, "<line bbox=\"%g %g %g %g\" wmode=\"%d\" dir=\"%g %g\" flags=\"%d\"",
943							line->bbox.x0, line->bbox.y0, line->bbox.x1, line->bbox.y1,
944							line->wmode,
945							line->dir.x, line->dir.y, line->flags);
946	
947					/* This is duplication of information, but it makes it MUCH easier to search for
948					 * text fragments in large output. */
949					{
950						int valid = 1;
951						fz_write_printf(ctx, out, " text=\"");
952						for (ch = line->first_char; ch; ch = ch->next)
953						{
954							if (valid)
955								valid = fz_is_valid_xml_char(ch->c);
956							xml_write_char(ctx, out, fz_range_limit_xml_char(ch->c));
957						}
958						if (!valid)
959						{
960							fz_write_printf(ctx, out, "\" hextext=\"");
961							for (ch = line->first_char; ch; ch = ch->next)
962							{
963								char text[8];
964								int n = fz_runetochar(text, ch->c);
965								for (i = 0; i < n; i++)
966									fz_write_printf(ctx, out, "%02x", text[i]);
967							}
968						}
969						fz_write_printf(ctx, out, "\"");
970					}
971	
972					if ((flags & FZ_STEXT_XML_FLAGS_CHARS) == 0)
973					{
974						fz_write_printf(ctx, out, "/>\n");
975					}
976					else
977					{
978						fz_write_printf(ctx, out, ">\n");
979	
980						for (ch = line->first_char; ch; ch = ch->next)
981						{
982							if (ch->font != font || ch->size != size)
983							{
984								const char *s;
985								if (font)
986									fz_write_string(ctx, out, "</font>\n");
987								font = ch->font;
988								size = ch->size;
989								s = name = font_full_name(ctx, font);
990								while (*s)
991								{
992									int c = *s++;
993									if (c < 32 || c >= 127)
994										break;
995								}
996								if (*s)
997									fz_write_printf(ctx, out, "<font hexname=%>", name);
998								else
999									fz_write_printf(ctx, out, "<font name=\"%s\"", name);
1000								fz_write_printf(ctx, out, " size=\"%g\">\n", size);
1001							}
1002							fz_write_printf(ctx, out, "<char c=\"");
1003							xml_write_char(ctx, out, ch->c);
1004							if (!fz_is_valid_xml_char(ch->c))
1005							{
1006								char text[8];
1007								int n = fz_runetochar(text, ch->c);
1008								fz_write_string(ctx, out, "\" hexc=\"");
1009								for (i = 0; i < n; i++)
1010									fz_write_printf(ctx, out, "%02x", text[i]);
1011							}
1012							fz_write_printf(ctx, out, "\" quad=\"%g %g %g %g %g %g %g %g\" x=\"%g\" y=\"%g\" bidi=\"%d\" color=\"#%06x\" alpha=\"#%02x\" flags=\"%d\"/>\n",
1013									ch->quad.ul.x, ch->quad.ul.y,
1014									ch->quad.ur.x, ch->quad.ur.y,
1015									ch->quad.ll.x, ch->quad.ll.y,
1016									ch->quad.lr.x, ch->quad.lr.y,
1017									ch->origin.x, ch->origin.y,
1018									ch->bidi,
1019									ch->argb & 0xFFFFFF,
1020									ch->argb>>24,
1021									ch->flags);
1022						}
1023	
1024						if (font)
1025							fz_write_string(ctx, out, "</font>\n");
1026	
1027						fz_write_string(ctx, out, "</line>\n");
1028					}
1029				}
1030				fz_write_string(ctx, out, "</block>\n");
1031				break;
1032	
1033			case FZ_STEXT_BLOCK_IMAGE:
1034				fz_write_printf(ctx, out, "<image ");
1035				if (flags & FZ_STEXT_XML_FLAGS_POINTERS)
1036					fz_write_printf(ctx, out, "p=\"%p\" ", block);
1037				fz_write_printf(ctx, out, "bbox=\"%g %g %g %g\" />\n",
1038						block->bbox.x0, block->bbox.y0, block->bbox.x1, block->bbox.y1);
1039				break;
1040	
1041			case FZ_STEXT_BLOCK_STRUCT:
1042				fz_write_printf(ctx, out, "<struct ");
1043				if (flags & FZ_STEXT_XML_FLAGS_POINTERS)
1044				{
1045					fz_write_printf(ctx, out, "p=\"%p\" d=\"%p\" ", block, block->u.s.down);
1046					if (block->u.s.down)
1047						fz_write_printf(ctx, out, "u=\"%p\" prt=\"%p\" ", block->u.s.down->up, block->u.s.down->parent);
1048				}
1049				fz_write_printf(ctx, out, "idx=\"%d\" bbox=\"%g %g %g %g\"", block->u.s.index,
1050						block->bbox.x0, block->bbox.y0, block->bbox.x1, block->bbox.y1);
1051				if (block->u.s.down)
1052					fz_write_printf(ctx, out, " raw=\"%s\" std=\"%s\"",
1053							block->u.s.down->raw, fz_structure_to_string(block->u.s.down->standard));
1054				fz_write_printf(ctx, out, ">\n");
1055				if (block->u.s.down)
1056					as_xml(ctx, block->u.s.down->first_block, out, flags);
1057				fz_write_printf(ctx, out, "</struct>\n");
1058				break;
1059	
1060			case FZ_STEXT_BLOCK_VECTOR:
1061				fz_write_printf(ctx, out, "<vector ");
1062				if (flags & FZ_STEXT_XML_FLAGS_POINTERS)
1063					fz_write_printf(ctx, out, "p=\"%p\" ", block);
1064				fz_write_printf(ctx, out, "bbox=\"%g %g %g %g\" stroke=\"%d\" rectangle=\"%d\" continues=\"%d\" argb=\"%08x\"/>\n",
1065						block->bbox.x0, block->bbox.y0, block->bbox.x1, block->bbox.y1,
1066						!!(block->u.v.flags & FZ_STEXT_VECTOR_IS_STROKED),
1067						!!(block->u.v.flags & FZ_STEXT_VECTOR_IS_RECTANGLE),
1068						!!(block->u.v.flags & FZ_STEXT_VECTOR_CONTINUES),
1069						block->u.v.argb);
1070				break;
1071	
1072			case FZ_STEXT_BLOCK_GRID:
1073				fz_write_printf(ctx, out, "<grid ");
1074				if (flags & FZ_STEXT_XML_FLAGS_POINTERS)
1075					fz_write_printf(ctx, out, "p=\"%p\" ", block);
1076				fz_write_printf(ctx, out, "xpos=\"");
1077				for (i = 0; i < block->u.b.xs->len; i++)
1078					fz_write_printf(ctx, out, "%g ", block->u.b.xs->list[i].pos);
1079				fz_write_printf(ctx, out, "\" xuncertainty=\"");
1080				for (i = 0; i < block->u.b.xs->len; i++)
1081					fz_write_printf(ctx, out, "%d ", block->u.b.xs->list[i].uncertainty);
1082				fz_write_printf(ctx, out, "\" xmaxuncertainty=\"%d\" ypos=\"", block->u.b.xs->max_uncertainty);
1083				for (i = 0; i < block->u.b.ys->len; i++)
1084					fz_write_printf(ctx, out, "%g ", block->u.b.ys->list[i].pos);
1085				fz_write_printf(ctx, out, "\" yuncertainty=\"");
1086				for (i = 0; i < block->u.b.ys->len; i++)
1087					fz_write_printf(ctx, out, "%d ", block->u.b.ys->list[i].uncertainty);
1088				fz_write_printf(ctx, out, "\" ymaxuncertainty=\"%d\" />\n", block->u.b.ys->max_uncertainty);
1089				break;
1090			}
1091			block = block->next;
1092		}
1093	}
