1119	/* JSON dump */
1120	
1121	static void
1122	as_json(fz_context *ctx, fz_stext_block *block, fz_output *out, float scale)
1123	{
1124		fz_stext_line *line;
1125		fz_stext_char *ch;
1126		int comma = 0;
1127	
1128		while (block)
1129		{
1130			if (comma)
1131				fz_write_string(ctx, out, ",");
1132			comma = 1;
1133	
1134			switch (block->type)
1135			{
1136			case FZ_STEXT_BLOCK_TEXT:
1137				fz_write_printf(ctx, out, "{%q:%q,", "type", "text");
1138				fz_write_printf(ctx, out, "%q:{", "bbox");
1139				fz_write_printf(ctx, out, "%q:%d,", "x", (int)(block->bbox.x0 * scale));
1140				fz_write_printf(ctx, out, "%q:%d,", "y", (int)(block->bbox.y0 * scale));
1141				fz_write_printf(ctx, out, "%q:%d,", "w", (int)((block->bbox.x1 - block->bbox.x0) * scale));
1142				fz_write_printf(ctx, out, "%q:%d},", "h", (int)((block->bbox.y1 - block->bbox.y0) * scale));
1143				fz_write_printf(ctx, out, "%q:[", "lines");
1144	
1145				for (line = block->u.t.first_line; line; line = line->next)
1146				{
1147					if (line != block->u.t.first_line)
1148						fz_write_string(ctx, out, ",");
1149					fz_write_printf(ctx, out, "{%q:%d,", "wmode", line->wmode);
1150					fz_write_printf(ctx, out, "%q:{", "bbox");
1151					fz_write_printf(ctx, out, "%q:%d,", "x", (int)(line->bbox.x0 * scale));
1152					fz_write_printf(ctx, out, "%q:%d,", "y", (int)(line->bbox.y0 * scale));
1153					fz_write_printf(ctx, out, "%q:%d,", "w", (int)((line->bbox.x1 - line->bbox.x0) * scale));
1154					fz_write_printf(ctx, out, "%q:%d,", "h", (int)((line->bbox.y1 - line->bbox.y0) * scale));
1155					fz_write_printf(ctx, out, "%q:%d},", "flags", line->flags);
1156	
1157					/* Since we force preserve-spans, the first char has the style for the entire line. */
1158					if (line->first_char)
1159					{
1160						fz_font *font = line->first_char->font;
1161						char *font_family = "sans-serif";
1162						char *font_weight = "normal";
1163						char *font_style = "normal";
1164						if (fz_font_is_monospaced(ctx, font)) font_family = "monospace";
1165						else if (fz_font_is_serif(ctx, font)) font_family = "serif";
1166						if (fz_font_is_bold(ctx, font)) font_weight = "bold";
1167						if (fz_font_is_italic(ctx, font)) font_style = "italic";
1168						fz_write_printf(ctx, out, "%q:{", "font");
1169						fz_write_printf(ctx, out, "%q:%q,", "name", fz_font_name(ctx, font));
1170						fz_write_printf(ctx, out, "%q:%q,", "family", font_family);
1171						fz_write_printf(ctx, out, "%q:%q,", "weight", font_weight);
1172						fz_write_printf(ctx, out, "%q:%q,", "style", font_style);
1173						fz_write_printf(ctx, out, "%q:%d},", "size", (int)(line->first_char->size * scale));
1174						fz_write_printf(ctx, out, "%q:%d,", "x", (int)(line->first_char->origin.x * scale));
1175						fz_write_printf(ctx, out, "%q:%d,", "y", (int)(line->first_char->origin.y * scale));
1176					}
1177	
1178					fz_write_printf(ctx, out, "%q:\"", "text");
1179					for (ch = line->first_char; ch; ch = ch->next)
1180					{
1181						if (ch->c == '"' || ch->c == '\\')
1182							fz_write_printf(ctx, out, "\\%c", ch->c);
1183						else if (ch->c < 32)
1184							fz_write_printf(ctx, out, "\\u%04x", ch->c);
1185						else
1186							fz_write_printf(ctx, out, "%C", ch->c);
1187					}
1188					fz_write_printf(ctx, out, "\"}");
1189				}
1190				fz_write_string(ctx, out, "]}");
1191				break;
1192	
1193			case FZ_STEXT_BLOCK_IMAGE:
1194				fz_write_printf(ctx, out, "{%q:%q,", "type", "image");
1195				fz_write_printf(ctx, out, "%q:{", "bbox");
1196				fz_write_printf(ctx, out, "%q:%d,", "x", (int)(block->bbox.x0 * scale));
1197				fz_write_printf(ctx, out, "%q:%d,", "y", (int)(block->bbox.y0 * scale));
1198				fz_write_printf(ctx, out, "%q:%d,", "w", (int)((block->bbox.x1 - block->bbox.x0) * scale));
1199				fz_write_printf(ctx, out, "%q:%d}}", "h", (int)((block->bbox.y1 - block->bbox.y0) * scale));
1200				break;
1201	
1202			case FZ_STEXT_BLOCK_STRUCT:
1203				fz_write_printf(ctx, out, "{%q:%q", "type", "structure");
1204				fz_write_printf(ctx, out, ",%q:%d", "index", block->u.s.index);
1205				if (block->u.s.down)
1206				{
1207					fz_write_printf(ctx, out, ",%q:%q", "raw", block->u.s.down->raw);
1208					fz_write_printf(ctx, out, ",%q:%q", "std", fz_structure_to_string(block->u.s.down->standard));
1209					fz_write_printf(ctx, out, ",%q:[", "contents");
1210					as_json(ctx, block->u.s.down->first_block, out, scale);
1211					fz_write_printf(ctx, out, "]");
1212				}
1213				fz_write_printf(ctx, out, "}");
1214				break;
1215	
1216			case FZ_STEXT_BLOCK_VECTOR:
1217				fz_write_printf(ctx, out, "{%q:%q", "type", "vector");
1218				fz_write_printf(ctx, out, ",%q:%d", "argb", block->u.v.argb);
1219				fz_write_printf(ctx, out, ",%q:%d", "stroked", !!(block->u.v.flags & FZ_STEXT_VECTOR_IS_STROKED));
1220				fz_write_printf(ctx, out, ",%q:%d", "rectangle", !!(block->u.v.flags & FZ_STEXT_VECTOR_IS_RECTANGLE));
1221				fz_write_printf(ctx, out, ",%q:%d", "continues", !!(block->u.v.flags & FZ_STEXT_VECTOR_CONTINUES));
1222				fz_write_printf(ctx, out, "}");
1223				break;
1224	
1225			case FZ_STEXT_BLOCK_GRID:
1226				fz_write_printf(ctx, out, "{%q:%q", "type", "grid");
1227				if (block->u.b.xs)
1228				{
1229					int x;
1230					fz_write_printf(ctx, out, ",\"xpos\":[");
1231					for (x = 0; x < block->u.b.xs->len; x++)
1232					{
1233						if (x != 0)
1234							fz_write_printf(ctx, out, ",");
1235						fz_write_printf(ctx, out, "%g", block->u.b.xs->list[x].pos);
1236					}
1237					fz_write_printf(ctx, out, "]\n");
1238				}
1239				if (block->u.b.ys)
1240				{
1241					int x;
1242					fz_write_printf(ctx, out, ",\"ypos\":[");
1243					for (x = 0; x < block->u.b.ys->len; x++)
1244					{
1245						if (x != 0)
1246							fz_write_printf(ctx, out, ",");
1247						fz_write_printf(ctx, out, "%g", block->u.b.ys->list[x].pos);
1248					}
1249					fz_write_printf(ctx, out, "]\n");
1250				}
1251				if (block->u.b.info)
1252				{
1253					int i, x, y;
1254					fz_write_printf(ctx, out, ",%q:%d", "w", block->u.b.info->w-1);
1255					fz_write_printf(ctx, out, ",%q:%d", "h", block->u.b.info->h-1);
1256					fz_write_printf(ctx, out, ",\"flags\":[");
1257					i = 0;
1258					for (y = 0; y < block->u.b.info->h; y++)
1259					{
1260						if (y != 0)
1261							fz_write_printf(ctx, out, ",");
1262						fz_write_printf(ctx, out, "[");
1263						for (x = 0; x < block->u.b.info->w; x++)
1264						{
1265							if (x != 0)
1266								fz_write_printf(ctx, out, ",");
1267							fz_write_printf(ctx, out, "%d", block->u.b.info->info[i++]);
1268						}
1269						fz_write_printf(ctx, out, "]\n");
1270					}
1271					fz_write_printf(ctx, out, "]\n");
1272	
1273				}
1274				fz_write_printf(ctx, out, "}");
1275				break;
1276	
1277			}
1278			block = block->next;
1279		}
1280	}
