1282	void
1283	fz_print_stext_page_as_json(fz_context *ctx, fz_output *out, fz_stext_page *page, float scale)
1284	{
1285		fz_write_printf(ctx, out, "{%q:[", "blocks");
1286	
1287		as_json(ctx, page->first_block, out, scale);
1288	
1289		fz_write_string(ctx, out, "]}");
1290	}
1291	
1292	/* Plain text */
1293	
1294	static void
1295	do_as_text(fz_context *ctx, fz_output *out, fz_stext_block *first_block)
1296	{
1297		fz_stext_block *block;
1298		fz_stext_line *line;
1299		fz_stext_char *ch;
1300		char utf[10];
1301		int i, n;
1302	
1303		for (block = first_block; block; block = block->next)
1304		{
1305			switch (block->type)
1306			{
1307			case FZ_STEXT_BLOCK_TEXT:
1308				for (line = block->u.t.first_line; line; line = line->next)
1309				{
1310					int break_line = 1;
1311					for (ch = line->first_char; ch; ch = ch->next)
1312					{
1313						if (ch->next == NULL && (line->flags & FZ_STEXT_LINE_FLAGS_JOINED) != 0)
1314						{
1315							break_line = 0;
1316							continue;
1317						}
1318						n = fz_runetochar(utf, ch->c);
1319						for (i = 0; i < n; i++)
1320							fz_write_byte(ctx, out, utf[i]);
1321					}
1322					if (break_line)
1323						fz_write_string(ctx, out, "\n");
1324				}
1325				fz_write_string(ctx, out, "\n");
1326				break;
1327			case FZ_STEXT_BLOCK_STRUCT:
1328				if (block->u.s.down != NULL)
1329					do_as_text(ctx, out, block->u.s.down->first_block);
1330				break;
1331			}
1332		}
1333	}
1334	
1335	void
1336	fz_print_stext_page_as_text(fz_context *ctx, fz_output *out, fz_stext_page *page)
1337	{
1338		do_as_text(ctx, out, page->first_block);
1339	}
1340	
1341	/* Text output writer */
1342	
1343	enum {
1344		FZ_FORMAT_TEXT,
1345		FZ_FORMAT_HTML,
1346		FZ_FORMAT_XHTML,
1347		FZ_FORMAT_STEXT_XML,
1348		FZ_FORMAT_STEXT_JSON,
1349	};
1350	
1351	typedef struct
1352	{
1353		fz_document_writer super;
1354		int format;
1355		int number;
1356		fz_stext_options opts;
1357		fz_stext_page *page;
1358		fz_output *out;
1359	} fz_text_writer;
1360	
1361	static fz_device *
1362	text_begin_page(fz_context *ctx, fz_document_writer *wri_, fz_rect mediabox)
1363	{
1364		fz_text_writer *wri = (fz_text_writer*)wri_;
1365		float s = wri->opts.scale;
1366	
1367		if (wri->page)
1368		{
1369			fz_drop_stext_page(ctx, wri->page);
1370			wri->page = NULL;
1371		}
1372	
1373		wri->number++;
1374	
1375		wri->page = fz_new_stext_page(ctx, fz_transform_rect(mediabox, fz_scale(s, s)));
1376		return fz_new_stext_device(ctx, wri->page, &wri->opts);
1377	}
1378	
1379	static void
1380	text_end_page(fz_context *ctx, fz_document_writer *wri_, fz_device *dev)
1381	{
1382		fz_text_writer *wri = (fz_text_writer*)wri_;
1383		float s = wri->opts.scale;
1384	
1385		fz_scale_stext_page(ctx, wri->page, s);
1386	
1387		fz_try(ctx)
1388		{
1389			fz_close_device(ctx, dev);
1390			switch (wri->format)
1391			{
1392			default:
1393			case FZ_FORMAT_TEXT:
1394				fz_print_stext_page_as_text(ctx, wri->out, wri->page);
1395				break;
1396			case FZ_FORMAT_HTML:
1397				fz_print_stext_page_as_html(ctx, wri->out, wri->page, wri->number);
1398				break;
1399			case FZ_FORMAT_XHTML:
1400				fz_print_stext_page_as_xhtml(ctx, wri->out, wri->page, wri->number);
1401				break;
1402			case FZ_FORMAT_STEXT_XML:
1403				fz_print_stext_page_as_xml(ctx, wri->out, wri->page, wri->number);
1404				break;
1405			case FZ_FORMAT_STEXT_JSON:
1406				if (wri->number > 1)
1407					fz_write_string(ctx, wri->out, ",");
1408				fz_print_stext_page_as_json(ctx, wri->out, wri->page, 1);
1409				break;
1410			}
1411		}
1412		fz_always(ctx)
1413		{
1414			fz_drop_device(ctx, dev);
1415			fz_drop_stext_page(ctx, wri->page);
1416			wri->page = NULL;
1417		}
1418		fz_catch(ctx)
1419			fz_rethrow(ctx);
1420	}
1421	
1422	static void
1423	text_close_writer(fz_context *ctx, fz_document_writer *wri_)
1424	{
1425		fz_text_writer *wri = (fz_text_writer*)wri_;
1426		switch (wri->format)
1427		{
1428		case FZ_FORMAT_HTML:
1429			fz_print_stext_trailer_as_html(ctx, wri->out);
1430			break;
1431		case FZ_FORMAT_XHTML:
1432			fz_print_stext_trailer_as_xhtml(ctx, wri->out);
1433			break;
1434		case FZ_FORMAT_STEXT_XML:
1435			fz_write_string(ctx, wri->out, "</document>\n");
1436			break;
1437		case FZ_FORMAT_STEXT_JSON:
1438			fz_write_string(ctx, wri->out, "]\n");
1439			break;
1440		}
1441		fz_close_output(ctx, wri->out);
1442	}
1443	
1444	static void
1445	text_drop_writer(fz_context *ctx, fz_document_writer *wri_)
1446	{
1447		fz_text_writer *wri = (fz_text_writer*)wri_;
1448		fz_drop_stext_page(ctx, wri->page);
1449		fz_drop_output(ctx, wri->out);
1450	}
1451	
1452	fz_document_writer *
1453	fz_new_text_writer_with_output(fz_context *ctx, const char *format, fz_output *out, const char *options)
1454	{
1455		fz_text_writer *wri = NULL;
1456	
1457		fz_var(wri);
1458	
1459		fz_try(ctx)
1460		{
1461			wri = fz_new_derived_document_writer(ctx, fz_text_writer, text_begin_page, text_end_page, text_close_writer, text_drop_writer);
1462			fz_parse_stext_options(ctx, &wri->opts, options);
1463	
1464			wri->format = FZ_FORMAT_TEXT;
1465			if (!strcmp(format, "text"))
1466			{
1467				wri->format = FZ_FORMAT_TEXT;
1468				wri->opts.flags &= ~FZ_STEXT_COLLECT_STYLES | FZ_STEXT_PRESERVE_IMAGES;
1469			}
1470			else if (!strcmp(format, "html"))
1471				wri->format = FZ_FORMAT_HTML;
1472			else if (!strcmp(format, "xhtml"))
1473				wri->format = FZ_FORMAT_XHTML;
1474			else if (!strcmp(format, "stext"))
1475				wri->format = FZ_FORMAT_STEXT_XML;
1476			else if (!strcmp(format, "stext.xml"))
1477				wri->format = FZ_FORMAT_STEXT_XML;
1478			else if (!strcmp(format, "stext.json"))
1479			{
1480				wri->format = FZ_FORMAT_STEXT_JSON;
1481				wri->opts.flags |= FZ_STEXT_PRESERVE_SPANS;
1482			}
1483	
1484			wri->out = out;
1485	
1486			switch (wri->format)
1487			{
1488			case FZ_FORMAT_HTML:
1489				fz_print_stext_header_as_html(ctx, wri->out);
1490				break;
1491			case FZ_FORMAT_XHTML:
1492				fz_print_stext_header_as_xhtml(ctx, wri->out);
1493				break;
1494			case FZ_FORMAT_STEXT_XML:
1495				fz_write_string(ctx, wri->out, "<?xml version=\"1.0\"?>\n");
1496				fz_write_string(ctx, wri->out, "<document>\n");
1497				break;
1498			case FZ_FORMAT_STEXT_JSON:
1499				fz_write_string(ctx, wri->out, "[");
1500				break;
1501			}
1502		}
1503		fz_catch(ctx)
1504		{
1505			fz_drop_output(ctx, out);
1506			fz_free(ctx, wri);
1507			fz_rethrow(ctx);
1508		}
1509	
1510		return (fz_document_writer*)wri;
1511	}
1512	
1513	fz_document_writer *
1514	fz_new_text_writer(fz_context *ctx, const char *format, const char *path, const char *options)
1515	{
1516		fz_output *out = fz_new_output_with_path(ctx, path ? path : "out.txt", 0);
1517		return fz_new_text_writer_with_output(ctx, format, out, options);
1518	}
